mapper.select:
SELECT *, seller_status status
FROM sellers


    seller_status = #{status}



    AND (
        company_name LIKE CONCAT("%", #{keyword}, "%")
        or representative_name LIKE CONCAT("%", #{keyword}, "%")
    )


ORDER BY seller_id DESC
LIMIT #{size} OFFSET #{offset}

SELECT count(*) FROM sellers
seller_status = #{status}
AND ( company_name LIKE CONCAT("%", #{keyword}, "%") or representative_name LIKE CONCAT("%", #{keyword}, "%") )

SELECT s.seller_id,s.user_id,s.company_name,u.photo_name,
/* 작가 전체 상품 리뷰 평균 */ (SELECT COALESCE(ROUND(AVG(r.rating), 1), 0) FROM products p JOIN reviews r ON p.product_id = r.product_id WHERE p.seller_id = s.seller_id AND p.status = 'APPROVED') AS review_avg,
/* 작가 전체 상품 리뷰 수 */ (SELECT COUNT(*) FROM products p JOIN reviews r ON p.product_id = r.product_id WHERE p.seller_id = s.seller_id AND p.status = 'APPROVED') AS review_count,
/* 작가 전체 상품 찜 수 */ (SELECT COUNT(*) FROM products p JOIN favorites f ON p.product_id = f.product_id WHERE p.seller_id = s.seller_id AND p.status = 'APPROVED') AS product_favorite_count
FROM sellers s JOIN users u ON s.user_id = u.user_id WHERE s.seller_id = #{seller_id}

SELECT oi.order_item_id, oi.order_id, oi.product_id, oi.price, oi.quantity, oi.status, oi.confirmed_at, oi.updated_at, p.name AS productName, p.image_l AS imageL, (oi.price * oi.quantity) AS subtotalAmount FROM order_items oi JOIN products p ON p.product_id = oi.product_id WHERE oi.order_id = #{order_id} AND p.seller_id = #{seller_id}
AND oi.status = #{status}
ORDER BY oi.order_item_id ASC
